```javascript
var TAU = 6.283;          // 2ПЂ
var PHI = 1.618;          // Golden ratio
var SQRT_HALF = 0.707;    // в€љ(1/2)

var config = {
  fieldStrength: 4000,     // Coulomb-like repulsion magnitude between nodes
  elasticModulus: 0.004,   // Spring stiffness for edges (default)
  convergenceRate: 0.92,   // Velocity damping factor per tick
  orbitalDecay: 0.0003,    // Center-seeking gravity strength
  particleCeiling: 40,     // Max number of sea particles alive at once
  streamDecay: 0.04,       // Particle drag/friction
  theta: 0.06              // Camera smoothing interpolation factor
};

// в”Ђв”Ђ Nodes в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

var nodes = [
  { id: "hub",      label: "Kieleth", r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: "alpha",    label: "Alpha",   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: "beta",     label: "Beta",    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: "gamma",    label: "Gamma",   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: "delta",    label: "Delta",   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: "epsilon",  label: "Epsilon", r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// в”Ђв”Ђ Edges (springs) в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

var edges = [
  { a: "hub", b: "alpha",   rest: 160, k: 0.006 },
  { a: "hub", b: "beta",    rest: 160, k: 0.005 },
  { a: "hub", b: "gamma",   rest: 170, k: 0.004 },
  { a: "hub", b: "delta",   rest: 170, k: 0.004 },
  { a: "hub", b: "epsilon", rest: 180, k: 0.003 },
  { a: "alpha", b: "beta",    rest: 200, k: 0.002 },
  { a: "gamma", b: "delta",   rest: 220, k: 0.002 },
  { a: "alpha", b: "epsilon", rest: 200, k: 0.002 }
];

// в”Ђв”Ђ Camera state в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

var camera       = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// в”Ђв”Ђ Sea particles в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

var particles = [];
var tickCount = 0;

// в”Ђв”Ђ Helper: find node by id в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

function findNode(id) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

// в”Ђв”Ђ Physics step в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

function physicsStep() {

  // 1) Coulomb repulsion вЂ” every pair of nodes repels
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx   = nodes[i].x - nodes[j].x;
      var dy   = nodes[i].y - nodes[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;

      var force = config.fieldStrength / (dist * dist);
      var fx    = (dx / dist) * force;
      var fy    = (dy / dist) * force;

      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // 2) Spring forces along edges (Hooke's law)
  for (var e = 0; e < edges.length; e++) {
    var nodeA = findNode(edges[e].a);
    var nodeB = findNode(edges[e].b);
    if (!nodeA || !nodeB) continue;

    var dx   = nodeB.x - nodeA.x;
    var dy   = nodeB.y - nodeA.y;
    var dist = Math.sqrt(dx * dx + dy * dy) || 1;

    var displacement = dist - edges[e].rest;
    var force = (edges[e].k || config.elasticModulus) * displacement;

    nodeA.vx += (dx / dist) * force;
    nodeA.vy += (dy / dist) * force;
    nodeB.vx -= (dx / dist) * force;
    nodeB.vy -= (dy / dist) * force;
  }

  // 3) Per-node: center gravity + velocity damping + position integration
  for (var n = 0; n < nodes.length; n++) {
    // Gentle pull toward center (400, 300)
    nodes[n].vx += (400 - nodes[n].x) * config.orbitalDecay;
    nodes[n].vy += (300 - nodes[n].y) * config.orbitalDecay;

    // Damping (convergenceRate = 0.92, so 8% velocity lost per tick)
    nodes[n].vx *= config.convergenceRate;
    nodes[n].vy *= config.convergenceRate;

    // Integrate position
    nodes[n].x += nodes[n].vx;
    nodes[n].y += nodes[n].vy;
  }
}

// в”Ђв”Ђ Spawn a decorative "sea" particle в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

function spawnParticle() {
  if (particles.length >= config.particleCeiling) return;

  // Pick a random node as the emission source
  var source = nodes[Math.floor(Math.random() * nodes.length)];
  var angle  = Math.random() * TAU;
  var speed  = 0.3 + Math.random() * SQRT_HALF;

  particles.push({
    x: source.x,
    y: source.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,            // 800вЂ“2000 ticks
    size: 0.8 + (Math.random() * PHI) * SQRT_HALF  // 0.8вЂ“1.95 px
  });
}

// в”Ђв”Ђ Update sea particles в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

function updateParticles() {
  for (var i = particles.length - 1; i >= 0; i--) {
    var p = particles[i];

    // Drag (streamDecay = 0.04, so multiply velocity by 0.995 each tick)
    p.vx *= 1 - config.streamDecay * 0.125;
    p.vy *= 1 - config.streamDecay * 0.125;

    // Integrate
    p.x += p.vx;
    p.y += p.vy;

    // Age and cull
    p.age++;
    if (p.age > p.maxAge) {
      particles.splice(i, 1);
    }
  }
}

// в”Ђв”Ђ Smooth camera tracking в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

function updateCamera() {
  camera.x    += (cameraTarget.x    - camera.x)    * config.theta;
  camera.y    += (cameraTarget.y    - camera.y)    * config.theta;
  camera.zoom += (cameraTarget.zoom - camera.zoom)  * config.theta;
}

// в”Ђв”Ђ Main tick в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

function tick() {
  physicsStep();
  updateParticles();
  updateCamera();

  // Spawn a new particle every 3rd frame
  if (tickCount % 3 === 0) spawnParticle();
  tickCount++;
}

setInterval(tick, 16);   // ~60 fps
```

